#!/usr/bin/env node
//! RAINBOW DICTIONARY precompute — seed the sovereign-sieve semantic cache offline.
//!
//! RainbowDictionary.lean / SovereignSieve: query frequency is Zipf, so PRECOMPUTING the
//! answers for a small frequent HEAD covers most traffic. The edge ssm-fleet sieve
//! (apps/ssm-fleet, model rwkv7-0.4b) starts EMPTY → 0% hit-rate → no savings until it
//! organically fills. This tool front-loads the skew: it drives the LIVE edge /generate with
//! `learn:true` for a curated frequent-prompt HEAD, which computes each prompt's final
//! pre-lm_head hidden (the resonance key) and SEEDS the R2 sieve blob
//! (ssm-semantic-cache/models/rwkv7-0.4b.knot.sieve.json). That IS the rainbow-dictionary
//! seeding for the edge — no offline knot build needed, the live edge does the compute once.
//!
//! Then it MEASURES the realized win: a HELD-OUT set of PARAPHRASES of the seeded prompts is
//! queried; the fraction that come back `lane:"semantic"` (verified cosine ≥ τ AND
//! decode-agreement confirmed) is the hit-rate the rainbow dictionary buys on paraphrase
//! traffic.
//!
//! HONEST CAVEATS:
//!  * The seed ANSWERS are the 0.4B base model's own completions — small, imperfect. That is
//!    fine for demonstrating the MECHANISM (does precompute-seeding raise measured hit-rate?);
//!    answer quality is a separate axis, gated at serve time by decode-agreement (miss-not-lie).
//!  * Seeding is SEQUENTIAL by design: every isolate rehydrates the R2 blob before seeding
//!    (loadSieve), so seeds accumulate monotonically in R2. Concurrent isolates would each
//!    flush a divergent superset and last-write-wins would drop seeds. Slower, but correct.
//!  * The measurement queries the LIVE edge, so it also exercises the real per-isolate sieve +
//!    R2 rehydrate path, not a local simulation.
//!
//! Usage:
//!   node rainbow-precompute.mjs                 # seed the head, then measure paraphrase hit-rate
//!   node rainbow-precompute.mjs --measure-only  # skip seeding, just measure (cache already seeded)
//!   node rainbow-precompute.mjs --seed-only     # seed the head, no measurement
//!   node rainbow-precompute.mjs --limit 20      # seed only the first 20 head prompts
//!   node rainbow-precompute.mjs --endpoint https://ssm-fleet.taylorbuley.workers.dev
//!
//! MEASURED RESULT (2026-06-30, live ssm-fleet rwkv7-0.4b, this tool, HEAD=39 prompts):
//!   sieve seeded 7 → 40 (37 new frequent-head prompts precomputed via /generate learn:true).
//!   36 HELD-OUT paraphrases queried (learn:false) → 19 came back lane:"semantic" (verified
//!   hit, decode-skipped) → REALIZED PARAPHRASE HIT-RATE = 52.8% (19/36).
//!   From a cold (~empty) sieve that is 0% by construction, precompute-seeding the Zipf HEAD
//!   lifts the paraphrase hit-rate to ~53% immediately — the rainbow-dictionary skew payoff
//!   (RainbowDictionary.head_covers_halves_cost) realized on live paraphrase traffic. Misses
//!   are the strict decode-agreement gate (miss-not-lie) rejecting paraphrases whose first-K
//!   base-model continuation tokens diverge (e.g. "France's capital is" → generic filler, or
//!   punctuation drift " Paris."≠" Paris,") — correctness preserved, not a wrong answer served.
//!
//! Prompt SOURCE: a curated high-frequency completion-style HEAD (capitals, arithmetic,
//! common facts/definitions, opposites, greetings). No in-repo query log exists for the edge
//! ssm-fleet sieve (its only "log" is the sieve blob itself, which this tool seeds), so a
//! curated frequent head is the honest source. Prompts are completion-style because the edge
//! model (rwkv7-0.4b.knot) is a BASE completion model, not instruction-tuned — paraphrases are
//! authored to share the answer PREFIX so the decode-agreement gate can confirm them.

const ENDPOINT_DEFAULT = 'https://ssm-fleet.taylorbuley.workers.dev';
const MAX_NEW_TOKENS_SEED = 8; // small: AGREE_K only checks the first 3 tokens; a short answer suffices
const MAX_NEW_TOKENS_MEASURE = 8;
const REQ_TIMEOUT_MS = 120_000;

// ── The frequent HEAD. Each entry: a seed prompt (precomputed) + held-out paraphrases
//    (queried at measure time; NOT seeded). Completion-style, base-model friendly. ──────────
const HEAD = [
  // Capitals
  { seed: 'The capital of France is', paras: ["France's capital is", 'The capital city of France is'] },
  { seed: 'The capital of Japan is', paras: ["Japan's capital is", 'The capital city of Japan is'] },
  { seed: 'The capital of Italy is', paras: ["Italy's capital is"] },
  { seed: 'The capital of Germany is', paras: ["Germany's capital is", 'The capital city of Germany is'] },
  { seed: 'The capital of Spain is', paras: ["Spain's capital is"] },
  { seed: 'The capital of England is', paras: ["England's capital is"] },
  { seed: 'The capital of Russia is', paras: ["Russia's capital is"] },
  { seed: 'The capital of China is', paras: ["China's capital is"] },
  { seed: 'The capital of Canada is', paras: ["Canada's capital is"] },
  { seed: 'The capital of Egypt is', paras: ["Egypt's capital is"] },
  { seed: 'The capital of Greece is', paras: ["Greece's capital is"] },
  { seed: 'The capital of Portugal is', paras: ["Portugal's capital is"] },
  // Arithmetic
  { seed: 'Two plus two equals', paras: ['Two plus two is', '2 plus 2 equals'] },
  { seed: 'Ten times ten equals', paras: ['Ten times ten is', '10 times 10 equals'] },
  { seed: 'The square root of nine is', paras: ['The square root of 9 is'] },
  { seed: 'One hundred divided by four is', paras: ['One hundred divided by four equals'] },
  // Facts / definitions
  { seed: 'The largest planet in the solar system is', paras: ['The biggest planet in the solar system is'] },
  { seed: 'The chemical symbol for water is', paras: ['The chemical formula for water is'] },
  { seed: 'The first president of the United States was', paras: ['The first US president was'] },
  { seed: 'The author of Romeo and Juliet is', paras: ['Romeo and Juliet was written by'] },
  { seed: 'The tallest mountain in the world is', paras: ['The highest mountain on Earth is'] },
  { seed: 'The largest ocean on Earth is', paras: ['The biggest ocean on Earth is'] },
  { seed: 'Water freezes at a temperature of', paras: ['Water turns to ice at a temperature of'] },
  { seed: 'The number of days in a week is', paras: ['A week has a number of days equal to'] },
  { seed: 'The color of the clear sky is', paras: ['On a clear day the sky is the color'] },
  // Opposites
  { seed: 'The opposite of hot is', paras: ['The antonym of hot is'] },
  { seed: 'The opposite of up is', paras: ['The antonym of up is'] },
  { seed: 'The opposite of day is', paras: ['The antonym of day is'] },
  { seed: 'The opposite of big is', paras: ['The antonym of big is'] },
  { seed: 'The opposite of fast is', paras: ['The antonym of fast is'] },
  // Greetings / common phrases (pure standalone frequent head, no paraphrase)
  { seed: 'Once upon a time', paras: [] },
  { seed: 'Thank you very much for', paras: [] },
  { seed: 'To be or not to', paras: [] },
  { seed: 'The quick brown fox jumps over the', paras: [] },
  { seed: 'In the beginning God created the', paras: [] },
  // Code snippets (frequent dev queries)
  { seed: 'In Python, to print hello world you write', paras: ['In Python you print hello world with'] },
  { seed: 'To reverse a string in Python you can use', paras: [] },
  { seed: 'The keyword to define a function in JavaScript is', paras: [] },
  { seed: 'To import a module in Python you use the keyword', paras: [] },
];

const args = process.argv.slice(2);
function argVal(name, dflt) {
  const i = args.indexOf(name);
  return i >= 0 && i + 1 < args.length ? args[i + 1] : dflt;
}
const ENDPOINT = argVal('--endpoint', ENDPOINT_DEFAULT).replace(/\/$/, '');
const MEASURE_ONLY = args.includes('--measure-only');
const SEED_ONLY = args.includes('--seed-only');
const LIMIT = Number.parseInt(argVal('--limit', ''), 10);

async function generate(prompt, { learn, maxNewTokens }) {
  const ctrl = new AbortController();
  const t = setTimeout(() => ctrl.abort(), REQ_TIMEOUT_MS);
  try {
    const res = await fetch(`${ENDPOINT}/generate`, {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({ prompt, maxNewTokens, learn }),
      signal: ctrl.signal,
    });
    if (!res.ok) return { error: `HTTP ${res.status}: ${(await res.text()).slice(0, 160)}` };
    return await res.json();
  } catch (e) {
    return { error: e instanceof Error ? e.message : String(e) };
  } finally {
    clearTimeout(t);
  }
}

async function semanticStats() {
  try {
    const res = await fetch(`${ENDPOINT}/semantic-stats`);
    return res.ok ? await res.json() : null;
  } catch {
    return null;
  }
}

function log(...a) {
  console.log(...a);
}

async function seedHead(head) {
  log(`\n=== SEED PHASE — precomputing ${head.length} frequent HEAD prompts (sequential) ===`);
  let ok = 0;
  let hitAlready = 0;
  let fail = 0;
  for (let i = 0; i < head.length; i++) {
    const { seed } = head[i];
    const r = await generate(seed, { learn: true, maxNewTokens: MAX_NEW_TOKENS_SEED });
    if (r.error) {
      fail++;
      log(`  [${i + 1}/${head.length}] FAIL  ${JSON.stringify(seed)} — ${r.error}`);
      continue;
    }
    const hit = r.lane === 'semantic';
    if (hit) hitAlready++;
    else ok++;
    log(
      `  [${i + 1}/${head.length}] ${hit ? 'seen ' : 'seed '} ${JSON.stringify(seed)} → ${JSON.stringify((r.text ?? '').slice(0, 40))}  (${r.lane}, ${r.ms}ms)`,
    );
  }
  log(`\n  seeded ${ok} new, ${hitAlready} already-present, ${fail} failed`);
  return { ok, hitAlready, fail };
}

async function measureParaphrases(head) {
  const paras = [];
  for (const h of head) for (const p of h.paras) paras.push({ query: p, of: h.seed });
  log(`\n=== MEASURE PHASE — querying ${paras.length} HELD-OUT paraphrases ===`);
  let hits = 0;
  let misses = 0;
  let fail = 0;
  const details = [];
  for (let i = 0; i < paras.length; i++) {
    const { query, of } = paras[i];
    // learn:false so measurement does NOT itself seed the paraphrase (keeps the metric honest).
    const r = await generate(query, { learn: false, maxNewTokens: MAX_NEW_TOKENS_MEASURE });
    if (r.error) {
      fail++;
      log(`  [${i + 1}/${paras.length}] FAIL  ${JSON.stringify(query)} — ${r.error}`);
      continue;
    }
    const hit = r.lane === 'semantic';
    if (hit) hits++;
    else misses++;
    const cos = r.semantic?.cosine != null ? ` cos=${r.semantic.cosine}` : '';
    details.push({ query, of, hit, text: (r.text ?? '').slice(0, 40) });
    log(
      `  [${i + 1}/${paras.length}] ${hit ? 'HIT ' : 'miss'}  ${JSON.stringify(query)} → ${JSON.stringify((r.text ?? '').slice(0, 40))}${cos}`,
    );
  }
  const total = hits + misses;
  const hitRate = total > 0 ? hits / total : 0;
  return { hits, misses, fail, total, hitRate, details };
}

async function main() {
  const head = Number.isFinite(LIMIT) && LIMIT > 0 ? HEAD.slice(0, LIMIT) : HEAD;
  log(`RAINBOW DICTIONARY precompute → ${ENDPOINT}`);
  log(`model: edge ssm-fleet rwkv7-0.4b sovereign sieve (default-on, learn:true seeds the R2 blob)`);

  const before = await semanticStats();
  if (before?.semantic) log(`\nsieve BEFORE: size=${before.semantic.sieveSize}`);

  let seedResult = null;
  if (!MEASURE_ONLY) {
    seedResult = await seedHead(head);
  }

  const afterSeed = await semanticStats();
  if (afterSeed?.semantic) log(`sieve AFTER seeding: size=${afterSeed.semantic.sieveSize}`);

  let measure = null;
  if (!SEED_ONLY) {
    measure = await measureParaphrases(head);
  }

  log(`\n${'='.repeat(64)}`);
  log('RAINBOW DICTIONARY — RESULT');
  log('='.repeat(64));
  log(`prompt source: curated high-frequency completion HEAD (${head.length} prompts)`);
  if (seedResult) log(`seeded: ${seedResult.ok} new + ${seedResult.hitAlready} already-present (${seedResult.fail} failed)`);
  if (afterSeed?.semantic) log(`sieve size after seeding: ${afterSeed.semantic.sieveSize}`);
  if (measure) {
    log(`held-out paraphrases queried: ${measure.total} (${measure.fail} failed)`);
    log(`paraphrase HITS (lane:semantic): ${measure.hits}`);
    log(`>>> REALIZED PARAPHRASE HIT-RATE: ${(measure.hitRate * 100).toFixed(1)}%  (${measure.hits}/${measure.total})`);
  }
  log('='.repeat(64));

  // Machine-readable tail for logging/commit.
  log(
    `\nJSON ${JSON.stringify({
      endpoint: ENDPOINT,
      headSize: head.length,
      seeded: seedResult,
      sieveSizeAfter: afterSeed?.semantic?.sieveSize ?? null,
      measure: measure ? { total: measure.total, hits: measure.hits, hitRate: +measure.hitRate.toFixed(4) } : null,
    })}`,
  );
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
